bool isAnagram(char* s, char* t) {
    int lenS = strlen(s);
    int lenT = strlen(t);

    if (lenS != lenT) return false;

    // Use array for lowercase letters
    int freq[26] = {0};

    // Count frequencies in s
    for (int i = 0; i < lenS; i++) {
        freq[s[i] - 'a']++;
    }

    // Decrease frequencies using t
    for (int i = 0; i < lenT; i++) {
        freq[t[i] - 'a']--;
        if (freq[t[i] - 'a'] < 0) return false;
    }

    // Check all frequencies are zero
    for (int i = 0; i < 26; i++) {
        if (freq[i] != 0) return false;
    }

    return true;
}

